export function generateNginx(ctx) {
    const serverName = ctx.hostname || 'localhost';
    const spaBlock = ctx.isSpa ? `
    # SPA Routing Fallback
    location / {
        try_files $uri $uri/ /index.html;
    }
` : `
    location / {
        try_files $uri $uri/ =404;
    }
`;
    return `# ---------------------------------------------------
# nginx.conf generated by docmd v${ctx.version}
# Project: ${ctx.title}
# https://docmd.io/deployment/nginx
# ---------------------------------------------------

server {
    listen 80;
    server_name ${serverName};
    root /usr/share/nginx/html;
    index index.html;

    # Security
    server_tokens off;
    add_header X-Content-Type-Options "nosniff" always;
    add_header X-Frame-Options "SAMEORIGIN" always;

    # GZIP Compression
    gzip on;
    gzip_vary on;
    gzip_proxied any;
    gzip_min_length 256;
    gzip_types
        text/plain
        text/css
        application/json
        application/javascript
        text/xml
        application/xml
        application/xml+rss
        text/javascript
        image/svg+xml;
${spaBlock}
    # Custom 404
    error_page 404 /404.html;

    # Cache Control for Static Assets
    location ~* \\.(?:ico|css|js|gif|jpe?g|png|webp|avif|woff2?|eot|ttf|otf|svg)$ {
        expires 6M;
        access_log off;
        add_header Cache-Control "public, immutable";
    }
}
`;
}
